// ============================================================================
// 踏月寻仙 - 系统 Schema（任务列表、声望系统、可参与机遇、当前处境）
// ============================================================================

import { z } from 'zod';

// 任务状态容错映射：兼容 AI 常见近义词，统一到三态
const 任务状态映射: Record<string, '进行中' | '已完成' | '已失败'> = {
  进行中: '进行中',
  进行: '进行中',
  处理中: '进行中',
  未完成: '进行中',
  待完成: '进行中',
  未开始: '进行中',
  已接取: '进行中',
  接取: '进行中',
  active: '进行中',

  已完成: '已完成',
  完成: '已完成',
  完成了: '已完成',
  已达成: '已完成',
  达成: '已完成',
  已结束: '已完成',
  结束: '已完成',
  done: '已完成',
  complete: '已完成',
  completed: '已完成',

  已失败: '已失败',
  失败: '已失败',
  失敗: '已失败',
  失败了: '已失败',
  中止: '已失败',
  终止: '已失败',
  放弃: '已失败',
  超时失败: '已失败',
  failed: '已失败',
  fail: '已失败',
};

// 任务类型容错映射：兼容 AI 常见写法，统一到任务系统支持的类型
const 任务类型映射: Record<string, '主线' | '支线' | '每日' | '临危受命' | '秘境探索'> = {
  主线: '主线',
  主任务: '主线',
  主线任务: '主线',
  main: '主线',

  支线: '支线',
  支线任务: '支线',
  side: '支线',
  sidequest: '支线',

  每日: '每日',
  日常: '每日',
  每日任务: '每日',
  daily: '每日',

  临危受命: '临危受命',
  紧急: '临危受命',
  紧急任务: '临危受命',
  urgent: '临危受命',

  秘境探索: '秘境探索',
  秘境: '秘境探索',
  探索: '秘境探索',
  秘境任务: '秘境探索',
  dungeon: '秘境探索',

  // “修炼任务”在当前 UI 语义上更接近支线，做保守归一
  修炼: '支线',
  修炼任务: '支线',
};

// 任务列表 Schema
export const QuestSchema = z.object({
  名称: z.string().prefault(''),
  类型: z
    .string()
    .transform(v => 任务类型映射[String(v).trim()] || '支线')
    .prefault('主线'),
  目标: z.string().prefault(''),
  状态: z
    .string()
    .transform(v => 任务状态映射[String(v).trim()] || '进行中')
    .prefault('进行中'),
  // 秘境专属字段（仅当类型为秘境探索时需要）
  秘境信息: z
    .object({
      域: z.enum(['天层', '神州', '东苍', '南炎', '西庚', '北冥', '下层', '四海']).optional(),
      危: z.coerce
        .number()
        .transform(v => _.clamp(v, 0, 100))
        .optional(),
      特: z.string().optional(),
      奖: z.union([z.array(z.string()), z.string().transform(v => (v ? [v] : []))]).prefault([]),
      限: z.string().optional(),
    })
    .optional(),
  创建时间: z
    .union([
      z.coerce.number(), // 兼容已有的时间戳
      z.string().transform(() => {
        // AI 输入修仙时间格式时，简化处理：直接用当前时间
        return Date.now();
      }),
    ])
    .prefault(() => Date.now()),
});

// 声望条目 Schema
export const ReputationEntrySchema = z.object({
  值: z.coerce
    .number()
    .transform(v => _.clamp(v, -100, 100))
    .prefault(0),
  关系: z.string().prefault('陌生'),
  更新时间: z.coerce.number().prefault(() => Date.now()),
});

// 声望系统 Schema（带自动关系计算 transform）
export const ReputationSystemSchema = z
  .record(z.string().describe('势力名'), ReputationEntrySchema)
  .prefault({})
  .transform(factions => {
    // 自动根据声望值计算关系描述
    return _(factions)
      .mapValues(faction => {
        const value = faction.值;
        let 自动关系: string;

        if (value >= 80) {
          自动关系 = '盟友';
        } else if (value >= 60) {
          自动关系 = '友善';
        } else if (value >= 30) {
          自动关系 = '友好';
        } else if (value >= 10) {
          自动关系 = '中立偏好';
        } else if (value >= -10) {
          自动关系 = '中立';
        } else if (value >= -30) {
          自动关系 = '中立偏恶';
        } else if (value >= -60) {
          自动关系 = '敌对';
        } else if (value >= -80) {
          自动关系 = '仇恨';
        } else {
          自动关系 = '不死不休';
        }

        // 如果用户手动设置了关系，优先使用用户设置；否则使用自动计算的关系
        const 最终关系 = faction.关系 && faction.关系 !== '陌生' ? faction.关系 : 自动关系;

        return {
          ...faction,
          关系: 最终关系,
        };
      })
      .value();
  });

// 可参与机遇 Schema
const 机遇类型映射: Record<string, '探索' | '任务' | '交易' | '结交' | '争夺' | '修炼' | '红颜' | '随机'> = {
  探索: '探索',
  任务: '任务',
  交易: '交易',
  结交: '结交',
  争夺: '争夺',
  修炼: '修炼',
  红颜: '红颜',
  随机: '随机',
  行动: '探索',
  冒险: '探索',
  战斗: '争夺',
  挑战: '争夺',
  社交: '结交',
  互动: '结交',
  双修: '红颜',
  亲密: '红颜',
  调情: '红颜',
  random: '随机',
};

export const OpportunitySchema = z.object({
  名称: z.coerce
    .string()
    .transform(v => String(v).trim())
    .prefault(''),
  来源: z.coerce
    .string()
    .transform(v => String(v).trim())
    .prefault(''), // 如：剧情推进、任务触发、NPC邀请、地点发现、时限事件
  类型: z
    .string()
    .transform(v => 机遇类型映射[String(v).trim()] || '探索')
    .prefault('探索'),
  描述: z.coerce
    .string()
    .transform(v => String(v).trim())
    .prefault(''),
  回报预期: z.coerce
    .string()
    .transform(v => String(v).trim())
    .prefault(''), // 如：中等灵石收益、可能获得功法线索
  风险评估: z.coerce
    .string()
    .transform(v => String(v).trim())
    .prefault(''), // 如：低风险、有战斗可能
  时限: z.coerce
    .string()
    .transform(v => String(v).trim())
    .optional(), // 如：本日结束前、三日内
  关联事件: z.coerce
    .string()
    .transform(v => String(v).trim())
    .optional(), // 关联的世界事件或任务
  优先级: z.coerce
    .number()
    .transform(v => _.clamp(v, 1, 5))
    .prefault(3), // 1-5，5最高
});

// 系统设置 Schema
export const SystemSettingsSchema = z
  .object({
    启用行动提示: z.boolean().prefault(true),
    修炼系统版本: z.coerce.number().prefault(1),
  })
  .prefault({});

// 行动系统设置 Schema
export const ActionSystemSettingsSchema = z
  .object({
    启用行动提示: z.boolean().prefault(true),
  })
  .prefault({});

